import{_ as e,o,c as t,ae as a}from"./chunks/framework.Dzr56EFm.js";const d=JSON.parse('{"title":"技术发布 - 2026-03-20","description":"","frontmatter":{"date":"2026-03-20T00:00:00.000Z","category":"Technology"},"headers":[],"relativePath":"daily/2026-03-20-technology.md","filePath":"daily/2026-03-20-technology.md"}'),n={name:"daily/2026-03-20-technology.md"};function s(g,r,i,p,l,h){return o(),t("div",null,[...r[0]||(r[0]=[a('<h1 id="技术发布-2026-03-20" tabindex="-1">技术发布 - 2026-03-20 <a class="header-anchor" href="#技术发布-2026-03-20" aria-label="Permalink to &quot;技术发布 - 2026-03-20&quot;">​</a></h1><blockquote><p>AI模型、API、开源项目、Agent、Infra</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日技术发布领域有10条重要资讯。</p><hr><h3 id="_1-微软代理框架-maf-概览" tabindex="-1">1. 微软代理框架（MAF）概览 <a class="header-anchor" href="#_1-微软代理框架-maf-概览" aria-label="Permalink to &quot;1. 微软代理框架（MAF）概览&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://github.com/microsoft/ai-agents-for-beginners/blob/main/02-explore-agentic-frameworks/README.md" target="_blank" rel="noreferrer">ai-agents-for-beginners/02-explore-agentic-frameworks/README ...</a></p><p><strong>一句话摘要</strong>: 微软代理框架提供构建AI代理的SDK。</p><p><strong>能解决什么问题</strong>: 解决如何利用Azure OpenAI模型创建企业级AI代理的问题。</p><p><strong>产品应用</strong>: 适用于构建具有工具调用、多步骤工作流和企业集成场景的生产级AI代理。</p><p><strong>示例场景</strong>: 构建一个能够与用户交互并执行特定任务的AI代理。</p><hr><h3 id="_2-欢迎使用微软代理框架" tabindex="-1">2. 欢迎使用微软代理框架！ <a class="header-anchor" href="#_2-欢迎使用微软代理框架" aria-label="Permalink to &quot;2. 欢迎使用微软代理框架！&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://github.com/microsoft/agent-framework" target="_blank" rel="noreferrer">Welcome to Microsoft Agent Framework! - GitHub</a></p><p><strong>一句话摘要</strong>: 微软代理框架支持.NET和Python，用于构建AI代理。</p><p><strong>能解决什么问题</strong>: 提供构建复杂AI代理和多代理工作流的解决方案。</p><p><strong>产品应用</strong>: 适用于需要构建智能对话代理和自动化工作流的产品。</p><p><strong>示例场景</strong>: 构建基于图的多代理工作流以自动化客服流程。</p><hr><h3 id="_3-kyrolabs-awesome-agents-ai代理的精选列表" tabindex="-1">3. kyrolabs/awesome-agents：AI代理的精选列表 <a class="header-anchor" href="#_3-kyrolabs-awesome-agents-ai代理的精选列表" aria-label="Permalink to &quot;3. kyrolabs/awesome-agents：AI代理的精选列表&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://github.com/kyrolabs/awesome-agents" target="_blank" rel="noreferrer">kyrolabs/awesome-agents: Awesome list of AI Agents - GitHub</a></p><p><strong>一句话摘要</strong>: GitHub上汇集了多种AI代理框架和工具</p><p><strong>能解决什么问题</strong>: 提供构建和部署AI代理的多样化解决方案</p><p><strong>产品应用</strong>: 可以应用于构建企业级AI代理，提高自动化和智能化水平</p><p><strong>示例场景</strong>: 使用OpenClaw框架创建个人AI助手</p><hr><h3 id="_4-dapr-agents-面向代理型ai系统的框架" tabindex="-1">4. Dapr Agents：面向代理型AI系统的框架 <a class="header-anchor" href="#_4-dapr-agents-面向代理型ai系统的框架" aria-label="Permalink to &quot;4. Dapr Agents：面向代理型AI系统的框架&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://github.com/dapr/dapr-agents" target="_blank" rel="noreferrer">Dapr Agents: A Framework for Agentic AI Systems - GitHub</a></p><p><strong>一句话摘要</strong>: Dapr Agents框架支持构建大规模、高弹性的AI代理系统。</p><p><strong>能解决什么问题</strong>: 解决大规模AI代理系统在复杂环境下的稳定性和协作问题。</p><p><strong>产品应用</strong>: 适用于需要大规模AI代理协作的业务场景，如自动化客服、智能调度等。</p><p><strong>示例场景</strong>: 使用Dapr Agents构建一个智能客服系统。</p><hr><h3 id="_5-微软代理框架github更新" tabindex="-1">5. 微软代理框架GitHub更新 <a class="header-anchor" href="#_5-微软代理框架github更新" aria-label="Permalink to &quot;5. 微软代理框架GitHub更新&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://github.com/microsoft/agent-framework/releases" target="_blank" rel="noreferrer">Releases · microsoft/agent-framework - GitHub</a></p><p><strong>一句话摘要</strong>: 微软代理框架发布多项修复和改进</p><p><strong>能解决什么问题</strong>: 解决代理框架在不同场景下的错误和性能问题</p><p><strong>产品应用</strong>: 适用于需要智能代理服务的软件产品，如聊天机器人</p><p><strong>示例场景</strong>: 在线客服系统使用代理框架提升响应效率</p><hr><h3 id="_6-gemini-3-1-pro-更智能的模型-应对最复杂的任务" tabindex="-1">6. Gemini 3.1 Pro：更智能的模型，应对最复杂的任务 <a class="header-anchor" href="#_6-gemini-3-1-pro-更智能的模型-应对最复杂的任务" aria-label="Permalink to &quot;6. Gemini 3.1 Pro：更智能的模型，应对最复杂的任务&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-1-pro/" target="_blank" rel="noreferrer">Gemini 3.1 Pro: A smarter model for your most complex tasks</a></p><p><strong>一句话摘要</strong>: 谷歌推出升级版AI模型Gemini 3.1 Pro，提升复杂问题解决能力。</p><p><strong>能解决什么问题</strong>: 解决需要高级推理能力的任务，如数据综合或解释复杂主题。</p><p><strong>产品应用</strong>: 可应用于消费者和开发者产品，通过API和企业级平台接入。</p><p><strong>示例场景</strong>: 在科学研究中，利用Gemini 3.1 Pro分析和解释复杂数据。</p><hr><h3 id="_7-gemini-3系列模型的google地图集成与api工具更新" tabindex="-1">7. Gemini 3系列模型的Google地图集成与API工具更新 <a class="header-anchor" href="#_7-gemini-3系列模型的google地图集成与api工具更新" aria-label="Permalink to &quot;7. Gemini 3系列模型的Google地图集成与API工具更新&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/innovation-and-ai/technology/developers-tools/gemini-api-tooling-updates/" target="_blank" rel="noreferrer">Gemini API tooling updates: context circulation, tool combos and ...</a></p><p><strong>一句话摘要</strong>: Gemini 3模型支持Google地图，提升位置感知能力。</p><p><strong>能解决什么问题</strong>: 解决现代智能代理在位置信息处理上的准确性和复杂性问题。</p><p><strong>产品应用</strong>: 适用于需要位置数据和复杂逻辑推理的智能代理产品。</p><p><strong>示例场景</strong>: 智能助手提供基于位置的实时交通信息和商业信息。</p><hr><h3 id="_8-2026年ai影响峰会-我们如何合作使ai惠及全球" tabindex="-1">8. 2026年AI影响峰会：我们如何合作使AI惠及全球 <a class="header-anchor" href="#_8-2026年ai影响峰会-我们如何合作使ai惠及全球" aria-label="Permalink to &quot;8. 2026年AI影响峰会：我们如何合作使AI惠及全球&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/intl/en-in/company-news/ai-impact-summit-2026-how-were-partnering-to-make-ai-work-for-everyone/" target="_blank" rel="noreferrer">AI Impact Summit 2026: How we&#39;re partnering to make AI work for ...</a></p><p><strong>一句话摘要</strong>: 宣布投资150亿美元建立印度AI基础设施，推出美印连接计划。</p><p><strong>能解决什么问题</strong>: 提高全球数字连接的覆盖范围、可靠性和韧性。</p><p><strong>产品应用</strong>: 可以应用于全球基础设施建设，提升政府服务效率。</p><p><strong>示例场景</strong>: 通过iGOT Karmayogi平台支持印度20万公务员培训。</p><hr><h3 id="_9-gemini-3-flash-为速度而生的前沿智能" tabindex="-1">9. Gemini 3 Flash：为速度而生的前沿智能 <a class="header-anchor" href="#_9-gemini-3-flash-为速度而生的前沿智能" aria-label="Permalink to &quot;9. Gemini 3 Flash：为速度而生的前沿智能&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/products-and-platforms/products/gemini/gemini-3-flash/" target="_blank" rel="noreferrer">Gemini 3 Flash: frontier intelligence built for speed - Google Blog</a></p><p><strong>一句话摘要</strong>: 谷歌发布Gemini 3 Flash，一款快速且性价比高的智能模型。</p><p><strong>能解决什么问题</strong>: 解决复杂推理、多模态理解和代理编码任务的速度和成本问题。</p><p><strong>产品应用</strong>: 可应用于代码模拟、游戏设计和多模态内容理解等实际产品开发。</p><p><strong>示例场景</strong>: 使用Gemini 3 Flash开发交互式游戏。</p><hr><h3 id="_10-gemini-embedding-2-首个原生多模态嵌入模型" tabindex="-1">10. Gemini Embedding 2：首个原生多模态嵌入模型 <a class="header-anchor" href="#_10-gemini-embedding-2-首个原生多模态嵌入模型" aria-label="Permalink to &quot;10. Gemini Embedding 2：首个原生多模态嵌入模型&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-embedding-2/" target="_blank" rel="noreferrer">Gemini Embedding 2: Our first natively multimodal embedding model</a></p><p><strong>一句话摘要</strong>: 谷歌发布首个多模态嵌入模型，实现不同媒体类型的嵌入空间映射。</p><p><strong>能解决什么问题</strong>: 解决不同类型媒体内容检索和分类的问题。</p><p><strong>产品应用</strong>: 可应用于多模态检索和分类，如文本、图像、视频和音频。</p><p><strong>示例场景</strong>: 个人健康应用中提升问答对的检索准确率。</p><hr>',75)])])}const b=e(n,[["render",s]]);export{d as __pageData,b as default};
